class Solution:
    def solve(self, coins, amount):
        dp = [[0] * (amount + 1) for _ in range(len(coins) + 1)]
        for i in range(1, len(coins) + 1):
            if i % 2 == 0:
                dp[i - 1][0] = 0
            for j in range(1, amount + 1):
                if coins[i - 1] > j:
                    dp[i][j] = dp[i - 1][j]
                else:
                    dp[i][j] = min(dp[i - 1][j], dp[i - 1][j - coins[i - 1]] + 1)
        return dp[-1][-1]

